"use strict";

const path = require("path");
const fs = require("fs");

const problemsFilePath = path.resolve(__dirname, "../../data/problems.json");

function readProblemsData() {
	const data = fs.readFileSync(problemsFilePath, "utf8");
	return JSON.parse(data);
}

/**
 * Get detailed problem info by problemId including component statistics.
 * Returns null if problem not found.
 * @param {string} problemId
 * @returns {object|null}
 */
function getProblemDetail(problemId) {
	const problemsData = readProblemsData();
	const problem = problemsData.find(p => p.problemId === problemId);
	if (!problem) return null;

	// Aggregate component statistics
	const components = problem.components || [];
	const languageCounts = {};
	const statusCounts = {};
	let maxPoints = 0;

	for (const comp of components) {
		// Count languages
		if (comp.language) {
			languageCounts[comp.language] = (languageCounts[comp.language] || 0) + 1;
		}
		// Count statuses
		if (comp.status) {
			statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
		}
		// Track max points
		if (typeof comp.points === "number" && comp.points > maxPoints) {
			maxPoints = comp.points;
		}
	}

	return {
		...problem,
		componentStats: {
			languageCounts,
			statusCounts,
			maxPoints,
		},
	};
}

module.exports = {
	getProblemDetail,
};
